     // C-(C2-X) --> X+(C-C2)
     if (match(Op1, m_Sub(m_ImmConstant(C2), m_Value(X))))
       return BinaryOperator::CreateAdd(X, ConstantExpr::getSub(C, C2));
+
+    // C - ((C1 - X) & C2) --> X & (C2 & Mask) where Mask = (2^Bits-1)
+    // if the sub has nuw and C == C1 & C2 and all bits of ~C2 are set in C1.
+    const APInt *C1Val, *C2Val;
+    if (match(Op1, m_OneUse(m_And(
+                       m_Sub(m_APInt(C1Val), m_Value(X)),
+                       m_APInt(C2Val))))) {
+      if (cast<BinaryOperator>(cast<Instruction>(Op1)->getOperand(0))
+              ->hasNoUnsignedWrap()) {
+        const APInt *C3Val;
+        if (match(Op0, m_APInt(C3Val)) &&
+            *C3Val == (*C1Val & *C2Val) &&
+            (*C1Val & ~*C2Val) == ~*C2Val) {
+          unsigned BW = I.getType()->getScalarSizeInBits();
+          APInt Mask = *C2Val & APInt::getLowBitsSet(BW, C1Val->getActiveBits());
+          return BinaryOperator::CreateAnd(X, ConstantInt::get(I.getType(), Mask));
+        }
+      }
+    }
